import { z } from "zod";

import { getBriefById } from "@/lib/briefs";
import { buildPreteachMessages } from "@/lib/contextBuilder";
import { callJudgeJSONWithFallback } from "@/lib/judgeClient";
import { PreteachResultSchema } from "@/lib/schemas";

const InitPreteachSchema = z.object({
  briefId: z.string().optional(),
});

export async function POST(request: Request) {
  const body = await request.json();
  const parsed = InitPreteachSchema.safeParse(body);
  if (!parsed.success) {
    return Response.json({ error: "Invalid preteach request." }, { status: 400 });
  }

  const brief = getBriefById(parsed.data.briefId);

  try {
    const preteach = await callJudgeJSONWithFallback({
      messages: buildPreteachMessages(brief),
      schema: PreteachResultSchema,
      temperature: 0.2,
      jsonRetries: 1,
      rateLimitRetriesPerModel: 1,
    });

    return Response.json(preteach);
  } catch (error) {
    console.error("Preteach generation failed:", error);
    return Response.json({ error: "Failed to generate preteach content." }, { status: 502 });
  }
}
